CREATE TABLE `common_task`( `id` bigint NOT NULL AUTO_INCREMENT COMMENT 'ID', `name` varchar(255) NOT NULL COMMENT '任务名称', `file_url` varchar(255) DEFAULT NULL COMMENT '下载文件地址', `type` tinyint NOT NULL COMMENT '任务类型 1：通用excel导出', `status` tinyint NOT NULL COMMENT '执行状态 0：待执行 1：执行中 2：成功 3：失败', `failure_count` tinyint DEFAULT '0' COMMENT '失败次数', `create_user_id` bigint NOT NULL COMMENT '创建人ID', `create_user_name` varchar(30) NOT NULL COMMENT '创建人名称', `create_time` datetime(3) DEFAULT NULL COMMENT '创建日期', `update_user_id` bigint DEFAULT NULL COMMENT '修改人ID', `update_user_name` varchar(30) DEFAULT NULL COMMENT '修改人名称', `update_time` datetime(3) DEFAULT NULL COMMENT '修改时间', `is_del` tinyint(1) DEFAULT '0' COMMENT '是否删除 1：已删除 0：未删除', `biz_type` tinyint NOT NULL COMMENT '业务类型 1：菜单 2：部门 3：角色 4：用户', `request_param` json DEFAULT NULL COMMENT '请求参数', PRIMARY KEY (`id`) USING BTREE) ENGINE=InnoDB AUTO_INCREMENT=1 DEFAULT CHARSET=utf8mb4  COMMENT='任务表';
